import React from "react";
import "../styles/home.css";
import Sostav from './Sostav';
import Matches from './Matches';
import Stadion from './Stadion';
import SpartakLogo from '../images/logoSpartak.webp';
import {
    BrowserRouter,
    Route,
    Link,
} from "react-router-dom";
import { Carousel } from "react-responsive-carousel";
import "react-responsive-carousel/lib/styles/carousel.min.css";
import newsPromize from "../images/newsPromise.webp";
import newsNikolson from "../images/newsNikolson.webp";
import newsDyarte from "../images/newsDyarte.webp";
import newsTavaresh from "../images/newsTavaresh.webp";
import glavFirst from "../images/glavFon.webp";
import glavSecond from "../images/frontImage.webp";
import Team from "../images/team.webp";
import newsMedals from "../images/newsMedals.webp";
import vkIcon from "../images/vkIcon.png";
import tgIcon from "../images/tgIcon.png";
import waIcon from "../images/waIcon.png";
import fbIcon from "../images/fbIcon.png";
import instIcon from "../images/instIcon.png";
import ytIcon from "../images/ytIcon.png";







function Home() {
    return (
        <div>
            <div className="frontContent">
                <Carousel
                    showArrows={false}
                    showStatus={false}
                    showThumbs={false}
                    infiniteLoop={true}
                    autoPlay={true}
                    interval={5000}
                    className="carouselWrapper">

                    <div key={1}>
                        <img src={glavFirst} alt="" className="carouselImage" />
                        <h1 className="carouselTitle">Новости</h1>
                    </div>
                    <div key={2}>
                        <img src={glavSecond} alt="" className="carouselImage" />
                        <h1 className="carouselTitle">Новости</h1>
                    </div>
                    <div key={3}>
                        <img src={Team} alt="" className="carouselImage" />
                        <h1 className="carouselTitle">Новости</h1>
                    </div>
                </Carousel>
            </div>
            <h1 className="newsTitle">Новости</h1>
            <div className="newsCards">
                <div className="newsCard">
                    <img src={newsPromize} alt="" />
                    <p>Квинси Промес — Winline Лучший игрок мая</p>
                    <h5>01 июня</h5>
                </div>

                <div className="newsCard">
                    <img src={newsNikolson} alt="" />
                    <p>Николсон примет участие в Золотом Кубке КОНКАКАФ</p>
                    <h5>01 июня</h5>
                </div>

                <div className="newsCard">
                    <img src={newsDyarte} alt="" />
                    <p>Дуарте вызван в сборную Парагвая</p>
                    <h5>01 июня</h5>
                </div>

                <div className="newsCard">
                    <img src={newsTavaresh} alt="" />
                    <p>Тавареш — в составе Португалии на Евро U-21</p>
                    <h5>31 мая</h5>
                </div>

                <div className="newsCard">
                    <img src={newsMedals} alt="" />
                    <p>Завершили сезон с бронзовыми медалями</p>
                    <h5>03 июня</h5>
                </div>

            </div>

            <footer className="homeFooter">
                <div className="homeFooterItems">
                    <img src={vkIcon} alt='' />
                    <img src={tgIcon} alt='' />
                    <img src={waIcon} alt='' />
                    <img src={fbIcon} alt='' />
                    <img src={instIcon} alt='' />
                    <img src={ytIcon} alt='' />
                </div>
                <div className="homeFooterItems">
                    <h3>Mag1strDM (Lavryxin Maxim)</h3>
                </div>
                <div className="homeFooterItems">
                    <h3>All rights reserved©</h3>
                </div>
                <div className="homeFooterItems">
                    <h4>2023</h4>
                </div>
            </footer>

        </div >
    );
}

export default Home;


