import React from "react";
import { useState } from "react";


const Counters = () => {
    const [count1, setCount1] = useState(0);
    const [count11, setCount11] = useState(0);
    const [count111, setCount111] = useState(0);
    function plus1() {
        return (
            <div>
                <h1 style={{color: 'white'}}>{count1}</h1>
                <button onClick={() => setCount1(count1 + 1)}>Увеличь на 1</button>
                <button onClick={() => setCount1(count1 - 1)}>Уменьши на 1</button>
            </div>
        )
    }


    function plus11() {
        return (
            <div>
                <h1 style={{color: 'white'}}>{count11}</h1>
                <button onClick={() => setCount11(count11 + 11)}>Увеличь на 11</button>
                <button onClick={() => setCount11(count11 - 11)}>Уменьши на 11</button>
            </div>
        )
    }


    function plus111() {
        return (
            <div>
                <h1 style={{color: 'white'}}>{count111}</h1>
                <button onClick={() => setCount111(count111 + 111)}>Увеличь на 111</button>
                <button onClick={() => setCount111(count111 - 111)}>Уменьши на 111</button>
            </div>
        )
    }

    return (
        <div>
            {plus1()}
            {plus11()}
            {plus111()}
        </div>
    )

}

export default Counters;