import React from 'react'
import "../styles/stadion.css";
import Stadium from "../images/stadium.webp";

function Stadion() {
  return (
    <div className="stadion">
      <div>
        <img src={Stadium} alt='' />
      </div>

      <div className="tablica">
        <table>
          <tbody>
            <tr>
              <td>
                <h4>ОТКРЫТИЕ</h4>
                <h1>5 сентября 2014 года</h1>
              </td>
            </tr>
            <tr>
              <td>
              <h4>РАЗМЕР ПОЛЯ</h4>
                <h1>105 x 68 метров</h1>
              </td>
            </tr>
            <tr>
              <td>
              <h4>ВМЕСТИМОСТЬ</h4>
                <h1>45 360 зрителей</h1>
              </td>
            </tr>
            <tr>
              <td>
              <h4>ОБЩАЯ ПЛОЩАДЬ</h4>
                <h1>53 758 метров²</h1>
              </td>
            </tr>
          </tbody>
        </table>
      </div>

    </div>
  )
}

export default Stadion;