import './styles/App.css';
import {
  BrowserRouter,
  Route,
  Link,
} from "react-router-dom";
import {Redirect} from 'react-router-dom';
import Tickets from './components/Tickets';
import Login from './components/Login';
import Home from './components/Home';
import Sostav from './components/Sostav';
import Matches from './components/Matches';
import Stadion from './components/Stadion';
import SpartakLogo from './images/logoSpartak.webp';
import {React, useState, useEffect} from 'react';
import BurgerMenu from './components/burgerMenu';

function App() {
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 567);
    };

    handleResize();

    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
    };
  }, []);
  return (
    <div>
      {isMobile && <BurgerMenu />}
      <div className="links">
      <BrowserRouter>
        <nav className="navigationBar">
            <Link to='/components/Home' className="navButtons">Главная</Link>
            <Link to='/components/Sostav' className="navButtons">Состав</Link>
            <Link to='/components/Matches' className="navButtons">Матчи</Link>
            <img className="navButtons" src={SpartakLogo} alt='' />
            <Link to='/components/Tickets' className="navButtons">Билеты</Link>
            <Link to='/components/Stadion' className="navButtons">Стадион</Link>
            <Link to='/components/Login' className="navButtons">Войти</Link>
        </nav>
        <div className="mainContent">
          <Route path='/components/Home'>
            <Home />
          </Route>
          <Route path='/components/Sostav'>
            <Sostav />
          </Route>
          <Route path='/components/Matches'>
            <Matches />
          </Route>
          <Route path='/components/Stadion'>
            <Stadion />
          </Route>
          <Route path='/components/Login'>
            <Login />
          </Route>
          <Route path='/components/Tickets'>
            <Tickets />
          </Route>
        </div>
        <Redirect to='/components/Home'/>
      </BrowserRouter>
    </div>
    </div>
  );
}

export default App;