import React from "react";
import "../styles/login.css";

function Login() {
    return (
        <div className="fullContent">
            <div>
                <h1 className="enterTitle">Войти в личный кабинет ФК «Спартак»</h1>
                <h3 className="enterTitle">У вас еще нет аккаунта? Зарегистрируйтесь</h3>
            </div>
            <div className="allForms">

                <div className="forms">
                    <input placeholder="Логин" className="inputForm" />
                </div>

                <div className="forms">
                    <input type="password" placeholder="Пароль" className="inputForm" />
                </div>

                <h5 className="forgot-password">Забыли пароль?</h5>

                <div className="forms">
                    <div className="inputFormEnter"><p>войти</p></div>
                </div>

            </div>
        </div>
    )
}

export default Login;